import { ChatFlow } from 'flowise/dist/src';
import { z } from 'zod';

const userSchema = z.object({
  name: z.string().min(1),
  age: z.number().int().min(18),
  email: z.string().email()
});

const detectSchemaHallucination = (nodeOutputs: any[]) => {
  const llmChainOutputs = nodeOutputs.filter(n => n.nodeType === 'LLMChain');
  return llmChainOutputs.map(output => {
    try {
      const parsed = userSchema.parse(output.json);
      return { valid: true, output };
    } catch (error) {
      return {
        valid: false,
        hallucination: true,
        error: (error as any).message,
        output,
        nodeId: output.nodeId
      };
    }
  }).filter(r => !r.valid);
};

const detectLowRelevanceDocs = (retrieverOutputs: any[]) => {
  const issues: any[] = [];
  retrieverOutputs.forEach(output => {
    if (output.nodeType === 'ConversationalRetrievalQAChain') {
      const docs = output.sourceDocuments || [];
      const lowRelevance = docs.filter(doc => 
        (doc.metadata?.score || 0) < 0.7
      );
      if (lowRelevance.length > 0) {
        issues.push({
          hallucination: true,
          type: 'low_relevance_docs',
          scoreThreshold: 0.7,
          badDocs: lowRelevance.length,
          totalDocs: docs.length,
          nodeId: output.nodeId
        });
      }
    }
  });
  return issues;
};

const detectSilentToolFailures = (toolOutputs: any[]) => {
  return toolOutputs
    .filter(output => output.nodeType === 'CustomTool' || output.nodeType === 'FunctionTool')
    .map(output => {
      const result = output.result || output.output || '';
      if (!result || result === '' || result === null || result === undefined) {
        return {
          hallucination: true,
          type: 'silent_tool_failure',
          toolName: output.toolName,
          emptyResult: true,
          nodeId: output.nodeId
        };
      }
      return null;
    })
    .filter(Boolean) as any[];
};

