import { Vex } from '@vex_dev/sdk';
import type { ChatFlow, INodeExecutionData } from 'flowise/dist/src';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY!
});

const flowiseCallback = {
  onNodeExecution: async (data: INodeExecutionData) => {
    // Run all three detection methods
    const hallucinations = [
      detectSchemaHallucination([data]),
      detectLowRelevanceDocs([data]),
      detectSilentToolFailures([data])
    ].flat();

    if (hallucinations.length > 0) {
      await vex.capture({
        type: 'hallucination',
        flowId: data.flowId,
        nodeId: data.nodeId,
        nodeType: data.nodeType,
        issues: hallucinations,
        input: data.input,
        output: data.output,
        metadata: {
          chatflowId: data.flowId,
          timestamp: new Date().toISOString()
        }
      });
    }
  }
};

// Add to Flowise chatflow configuration
chatflow.callbacks = [flowiseCallback];
